> I'm trying to add again barriers that appeared to make sense and see if this is fixed...

Not so easy, I tried a bunch of things:

<details>

```
diff --git a/net/ipv4/udp.c b/net/ipv4/udp.c
index 8accbf4cb295..4f9c585aec1f 100644
--- a/net/ipv4/udp.c
+++ b/net/ipv4/udp.c
@@ -327,6 +327,7 @@ int udp_lib_get_port(struct sock *sk, unsigned short snum,
                        goto fail_unlock;
                }

+               smp_wmb();
                sock_set_flag(sk, SOCK_RCU_FREE);

                sk_add_node_rcu(sk, &hslot->head);
@@ -434,6 +435,10 @@ static struct sock *udp4_lib_lookup2(const struct net *net,

        result = NULL;
        badness = 0;
+
+       rcu_read_lock();
+
+       smp_rmb();
        udp_portaddr_for_each_entry_rcu(sk, &hslot2->head) {
                need_rescore = false;
 rescore:
@@ -458,8 +463,10 @@ static struct sock *udp4_lib_lookup2(const struct net *net,
                        }

                        /* Fall back to scoring if group has connections */
-                       if (!reuseport_has_conns(sk))
+                       if (!reuseport_has_conns(sk)) {
+                               rcu_read_unlock();
                                return result;
+                       }

                        /* Reuseport logic returned an error, keep original score. */
                        if (IS_ERR(result))
@@ -475,6 +482,9 @@ static struct sock *udp4_lib_lookup2(const struct net *net,
                        goto rescore;
                }
        }
+
+       rcu_read_unlock();
+
        return result;
 }

```
</details>

but no luck so far. I didn't try reintroducing an equivalent of hlist_for_each_entry_rcu_safenext() as removed by commit 88ab1932eac7. I guess the problem is more subtle than I expected at this point.

Just adding these prints makes the shell script reproducer fail by itself reliably on the first loop (without need for bats and Podman in parallel). Unless I `taskset -c1` it, of course: in that case, it never fails.

<details>

```
diff --git a/net/ipv4/udp.c b/net/ipv4/udp.c
index 8accbf4cb295..9ddf42e35335 100644
--- a/net/ipv4/udp.c
+++ b/net/ipv4/udp.c
@@ -429,12 +429,14 @@ static struct sock *udp4_lib_lookup2(const struct net *net,
                                     struct sk_buff *skb)
 {
        struct sock *sk, *result;
-       int score, badness;
+       int score, badness, count = 0, ne = 0;
        bool need_rescore;

        result = NULL;
        badness = 0;
+
        udp_portaddr_for_each_entry_rcu(sk, &hslot2->head) {
+               count++;
                need_rescore = false;
 rescore:
                score = compute_score(need_rescore ? result : sk, net, saddr,
@@ -450,6 +452,8 @@ static struct sock *udp4_lib_lookup2(const struct net *net,
                                continue;
                        }

+                       ne = 1;
+
                        result = inet_lookup_reuseport(net, sk, skb, sizeof(struct udphdr),
                                                       saddr, sport, daddr, hnum, udp_ehashfn);
                        if (!result) {
@@ -475,6 +479,12 @@ static struct sock *udp4_lib_lookup2(const struct net *net,
                        goto rescore;
                }
        }
+
+       if (!result) {
+               pr_err("%s:%i, score: %i, badness: %i, entries: %i, ne: %i",
+                       __func__, __LINE__, score, badness, count, ne);
+       }
+
        return result;
 }

@@ -2422,8 +2432,10 @@ int __udp4_lib_rcv(struct sk_buff *skb, struct udp_table *udptable,

        sk = inet_steal_sock(net, skb, sizeof(struct udphdr), saddr, uh->source, daddr, uh->dest,
                             &refcounted, udp_ehashfn);
-       if (IS_ERR(sk))
+       if (IS_ERR(sk)) {
+               pr_err("%s:%i, steal error", __func__, __LINE__);
                goto no_sk;
+       }

        if (sk) {
                struct dst_entry *dst = skb_dst(skb);
@@ -2435,6 +2447,7 @@ int __udp4_lib_rcv(struct sk_buff *skb, struct udp_table *udptable,
                ret = udp_unicast_rcv_skb(sk, skb, uh);
                if (refcounted)
                        sock_put(sk);
+               pr_err("%s:%i, steal found", __func__, __LINE__);
                return ret;
        }

@@ -2445,6 +2458,9 @@ int __udp4_lib_rcv(struct sk_buff *skb, struct udp_table *udptable,
        sk = __udp4_lib_lookup_skb(skb, uh->source, uh->dest, udptable);
        if (sk)
                return udp_unicast_rcv_skb(sk, skb, uh);
+
+       pr_err("%s:%i lib_lookup_skb error", __func__, __LINE__);
+
 no_sk:
        if (!xfrm4_policy_check(NULL, XFRM_POLICY_IN, skb))
                goto drop;
@@ -2463,6 +2479,7 @@ int __udp4_lib_rcv(struct sk_buff *skb, struct udp_table *udptable,
         * don't wanna listen.  Ignore it.
         */
        sk_skb_reason_drop(sk, skb, drop_reason);
+       pr_err("=== %s:%i drop", __func__, __LINE__);
        return 0;

 short_packet:
